// ─── Part X: Full Diagnostic Bundle ──────────────────────────────────

export interface TestimonyDiagnostic {
  readonly blazePower: number;
  readonly testimonialPower: number;
  readonly narrativePower: number;
  readonly amplification: number;
  readonly isNarrative: boolean;
  readonly isFullyVulnerable: boolean;
  readonly phantomCount: 0;
  readonly maintenanceCost: 0;
  readonly meetsClinamenThreshold: boolean;
}

/** Full diagnostic for a testimony. */
export function diagnoseTestimony(t: Testimony): TestimonyDiagnostic {
  return {
    blazePower: blazePower(t.bearingTree.blaze),
    testimonialPower: testimonialPower(t),
    narrativePower: narrativePower(t),
    amplification: vulnerabilityAmplification(t),
    isNarrative: isNarrative(t),
    isFullyVulnerable: isFullyVulnerable(t),
    phantomCount: 0,
    maintenanceCost: 0,
    meetsClinamenThreshold: meetsClinamenThreshold(t.bearingTree.blaze),
  };
}

export interface ReceiverTriangulationDiagnostic {
  readonly triangulation: TriangulationResult;
  readonly gaitSequence: number[];
  readonly maxGait: number;
  readonly totalVoidWalk: number;
  readonly isCalibrated: boolean;
}

/** Full triangulation diagnostic for a receiver walking a chain. */
export function diagnoseTriangulation(
  r: Receiver,
  chain: TestimonyChain
): ReceiverTriangulationDiagnostic {
  const firstBearing = chain.bearings[0];
  const tri = firstBearing
    ? triangulate(r, firstBearing)
    : {
        receiverPosition: r.position,
        cornerPosition: r.position,
        gait: 0,
        landauerHeat: 0,
        withinCapacity: true,
      };
  return {
    triangulation: tri,
    gaitSequence: gaitSequence(r, chain),
    maxGait: maxGait(r, chain),
    totalVoidWalk: totalVoidWalk(r, chain),
    isCalibrated: isCalibrated(r, chain),
  };
}
